import { Howl, staticFiles } from "@hushkey/howl";
import { reactEngine } from "@hushkey/howl-react";
import { apiConfig, type State } from "../howl.config.ts";

// Page rendering is a registered engine — reactEngine() from
// @hushkey/howl-react or vueEngine() from @hushkey/howl-vue. There is no
// implicit default; registering page routes without an engine throws.
export const app = new Howl<State>({ logger: true, engines: { react: reactEngine() } });

app.use(staticFiles());
app.fsApiRoutes(apiConfig);
app.fsClientRoutes();

export default { app };
